// pages/RestaurantListingPage.jsx
// Route: /explore?cuisine=chinese  OR  /explore?dish=momos  OR  /explore?cuisine=chinese&dish=momos
//
// React Router v6 usage:
//   <Route path="/explore" element={<RestaurantListingPage />} />
//
// Link from anywhere:
//   <Link to="/explore?cuisine=chinese">Chinese</Link>
//   <Link to="/explore?dish=paneer">Paneer</Link>
//   <Link to="/explore?cuisine=indian&dish=biryani">Biryani</Link>

import { useState, useMemo, useEffect, useRef } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { useSelector } from "react-redux";
import { selectEnrichedBindings } from "../store/foodSlice";

// ── Palette ───────────────────────────────────────────────────────
const CUISINE_PALETTE = {
  chinese:      { grad: "135deg,#FF922B,#E64D00", accent: "#FF922B", soft: "#FF922B18", emoji: "🥡" },
  indian:       { grad: "135deg,#FF6B9D,#FF3D7F", accent: "#FF6B9D", soft: "#FF6B9D18", emoji: "🍛" },
  italian:      { grad: "135deg,#4D96FF,#1565C0", accent: "#4D96FF", soft: "#4D96FF18", emoji: "🍝" },
  soups:        { grad: "135deg,#38D9A9,#00897B", accent: "#38D9A9", soft: "#38D9A918", emoji: "🍲" },
  dessert:      { grad: "135deg,#CC5DE8,#9C27B0", accent: "#CC5DE8", soft: "#CC5DE818", emoji: "🍰" },
  "sweet dish": { grad: "135deg,#FFD93D,#FFC300", accent: "#FFD93D", soft: "#FFD93D18", emoji: "🍭" },
};
const DEFAULT_PALETTE = { grad: "135deg,#a78bfa,#7c3aed", accent: "#a78bfa", soft: "#a78bfa18", emoji: "🍽️" };

function getPalette(cuisineKey) {
  return CUISINE_PALETTE[cuisineKey?.toLowerCase()] ?? DEFAULT_PALETTE;
}

// ── Star rating visual ────────────────────────────────────────────
function Stars({ rating }) {
  const val = parseFloat(rating) || 0;
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 3 }}>
      {[1,2,3,4,5].map(i => (
        <svg key={i} width={12} height={12} viewBox="0 0 24 24">
          <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"
            fill={i <= Math.round(val) ? "#FFD93D" : "rgba(255,255,255,0.15)"}
            stroke="none"
          />
        </svg>
      ))}
      <span style={{ color: "#FFD93D", fontFamily: "'Space Mono',monospace", fontSize: "0.75rem", marginLeft: 2 }}>
        {val > 0 ? val.toFixed(1) : "–"}
      </span>
    </div>
  );
}

// ── Restaurant Card ───────────────────────────────────────────────
function RestaurantCard({ item, idx, accent, soft }) {
  const { dishDetails: dish, restaurantDetails: res } = item;
  const [hovered, setHovered] = useState(false);

  if (!dish || !res) return null;

  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: hovered ? soft : "rgba(255,255,255,0.032)",
        border: `1px solid ${hovered ? accent + "55" : "rgba(255,255,255,0.08)"}`,
        borderRadius: 22,
        padding: 0,
        overflow: "hidden",
        transition: "all 0.28s cubic-bezier(.34,1.56,.64,1)",
        transform: hovered ? "translateY(-4px) scale(1.01)" : "none",
        boxShadow: hovered ? `0 16px 48px ${accent}28, 0 4px 16px rgba(0,0,0,0.4)` : "0 2px 12px rgba(0,0,0,0.25)",
        animation: `cardIn 0.55s cubic-bezier(.34,1.56,.64,1) ${idx * 0.065}s both`,
        cursor: "pointer",
      }}
    >
      {/* Top image band */}
      <div style={{
        height: 130, position: "relative", overflow: "hidden",
        background: `linear-gradient(${accent}22, ${accent}08)`,
      }}>
        {res.res_image ? (
          <img src={res.res_image} alt={res.name}
            style={{ width: "100%", height: "100%", objectFit: "cover", opacity: 0.85 }} />
        ) : (
          <div style={{
            width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center",
            fontSize: "3.5rem",
          }}>🏪</div>
        )}
        {/* Rating badge overlay */}
        <div style={{
          position: "absolute", top: 12, right: 12,
          background: "rgba(0,0,0,0.65)", backdropFilter: "blur(8px)",
          borderRadius: 10, padding: "4px 10px",
          border: `1px solid rgba(255,255,255,0.1)`,
        }}>
          <Stars rating={res.rating} />
        </div>
        {/* Dish image pill */}
        {dish.dish_image_link && (
          <div style={{
            position: "absolute", bottom: -20, left: 20,
            width: 50, height: 50, borderRadius: "50%",
            border: `3px solid ${accent}`,
            overflow: "hidden", boxShadow: `0 4px 16px ${accent}55`,
          }}>
            <img src={dish.dish_image_link} alt={dish.dish_name}
              style={{ width: "100%", height: "100%", objectFit: "cover" }} />
          </div>
        )}
      </div>

      {/* Body */}
      <div style={{ padding: "28px 20px 20px" }}>
        <div style={{
          fontFamily: "'Clash Display', 'Nunito', sans-serif", fontWeight: 800,
          fontSize: "1.05rem", color: "#fff", marginBottom: 6,
          whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
        }}>
          {res.name}
        </div>

        <div style={{ display: "flex", flexWrap: "wrap", gap: 6, marginBottom: 10 }}>
          <span style={{
            background: `${accent}22`, color: accent, borderRadius: 8,
            padding: "3px 11px", fontSize: "0.72rem", fontWeight: 700,
            fontFamily: "'Nunito',sans-serif", border: `1px solid ${accent}44`,
          }}>
            {dish.dish_name}
          </span>
          <span style={{
            background: "rgba(255,255,255,0.06)", color: "rgba(255,255,255,0.45)",
            borderRadius: 8, padding: "3px 11px", fontSize: "0.72rem",
            fontFamily: "'Nunito',sans-serif", textTransform: "capitalize",
          }}>
            {item.cuisine}
          </span>
        </div>
      </div>
    </div>
  );
}

// ── Search bar ────────────────────────────────────────────────────
function SearchBar({ value, onChange, accent }) {
  const inputRef = useRef(null);
  const [focused, setFocused] = useState(false);

  return (
    <div style={{
      position: "relative",
      border: `1.5px solid ${focused ? accent : "rgba(255,255,255,0.12)"}`,
      borderRadius: 16, overflow: "hidden",
      background: focused ? `${accent}0d` : "rgba(255,255,255,0.04)",
      transition: "border-color 0.25s, background 0.25s, box-shadow 0.25s",
      boxShadow: focused ? `0 0 0 3px ${accent}22` : "none",
    }}>
      <div style={{
        position: "absolute", left: 16, top: "50%", transform: "translateY(-50%)",
        color: focused ? accent : "rgba(255,255,255,0.3)", transition: "color 0.25s",
        pointerEvents: "none",
      }}>
        <svg width={18} height={18} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.2} strokeLinecap="round">
          <circle cx={11} cy={11} r={8} />
          <line x1={21} y1={21} x2={16.65} y2={16.65} />
        </svg>
      </div>
      <input
        ref={inputRef}
        value={value}
        onChange={e => onChange(e.target.value)}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        placeholder="Search restaurants or dishes…"
        style={{
          width: "100%", background: "none", border: "none", outline: "none",
          padding: "14px 44px 14px 46px",
          fontFamily: "'Nunito', sans-serif", fontWeight: 600,
          fontSize: "0.95rem", color: "#fff",
          caretColor: accent,
        }}
      />
      {value && (
        <button onClick={() => { onChange(""); inputRef.current?.focus(); }} style={{
          position: "absolute", right: 14, top: "50%", transform: "translateY(-50%)",
          background: "rgba(255,255,255,0.1)", border: "none", borderRadius: "50%",
          width: 22, height: 22, cursor: "pointer", color: "rgba(255,255,255,0.6)",
          display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14,
          lineHeight: 1,
        }}>×</button>
      )}
    </div>
  );
}

// ── Active filter chip ────────────────────────────────────────────
function FilterChip({ label, accent, onRemove }) {
  return (
    <div style={{
      display: "inline-flex", alignItems: "center", gap: 6,
      background: `${accent}22`, border: `1px solid ${accent}55`,
      borderRadius: 20, padding: "5px 12px 5px 14px",
      fontFamily: "'Nunito',sans-serif", fontWeight: 700,
      fontSize: "0.8rem", color: accent,
      animation: "chipIn 0.3s cubic-bezier(.34,1.56,.64,1) both",
    }}>
      {label}
      {onRemove && (
        <button onClick={onRemove} style={{
          background: `${accent}33`, border: "none", borderRadius: "50%",
          width: 18, height: 18, cursor: "pointer", color: accent,
          display: "flex", alignItems: "center", justifyContent: "center",
          fontSize: 12, lineHeight: 1, padding: 0,
        }}>×</button>
      )}
    </div>
  );
}

// ── Sort selector ─────────────────────────────────────────────────
function SortSelector({ value, onChange, accent }) {
  const options = [
    { value: "default", label: "Default" },
    { value: "rating_desc", label: "Rating ↓" },
    { value: "rating_asc",  label: "Rating ↑" },
    { value: "name_asc",    label: "A → Z" },
  ];
  return (
    <div style={{ position: "relative" }}>
      <select
        value={value}
        onChange={e => onChange(e.target.value)}
        style={{
          background: "rgba(255,255,255,0.05)", border: `1px solid rgba(255,255,255,0.12)`,
          borderRadius: 12, padding: "10px 36px 10px 14px",
          color: "#fff", fontFamily: "'Nunito',sans-serif", fontWeight: 700, fontSize: "0.82rem",
          cursor: "pointer", outline: "none", appearance: "none", WebkitAppearance: "none",
        }}
      >
        {options.map(o => <option key={o.value} value={o.value} style={{ background: "#1a0533" }}>{o.label}</option>)}
      </select>
      <div style={{ position: "absolute", right: 12, top: "50%", transform: "translateY(-50%)", pointerEvents: "none", color: "rgba(255,255,255,0.4)", fontSize: 10 }}>▼</div>
    </div>
  );
}

// ── Main Page ─────────────────────────────────────────────────────
export default function RestaurantListingPage() {
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();

  const cuisineParam = searchParams.get("cuisine") ?? "";
  const dishParam    = searchParams.get("dish")    ?? "";

  const [searchQuery, setSearchQuery] = useState("");
  const [sortMode, setSortMode] = useState("default");
  const [mounted, setMounted] = useState(false);

  useEffect(() => { setTimeout(() => setMounted(true), 50); }, []);

  // Pull all enriched bindings from Redux
  const allBindings = useSelector(selectEnrichedBindings);

  // Determine active palette (cuisine takes priority for colour theme)
  const palette = getPalette(cuisineParam || dishParam);

  // ── Core filter: cuisine + dish params ──────────────────────────
  const paramFiltered = useMemo(() => {
    return allBindings.filter(b => {
      if (!b.dishDetails || !b.restaurantDetails) return false;
      const cuisineMatch = cuisineParam
        ? b.cuisine?.toLowerCase() === cuisineParam.toLowerCase()
        : true;
      const dishMatch = dishParam
        ? b.dish?.toLowerCase() === dishParam.toLowerCase()
        : true;
      return cuisineMatch && dishMatch;
    });
  }, [allBindings, cuisineParam, dishParam]);

  // ── Search filter on top ────────────────────────────────────────
  const searchFiltered = useMemo(() => {
    if (!searchQuery.trim()) return paramFiltered;
    const q = searchQuery.toLowerCase();
    return paramFiltered.filter(b =>
      b.restaurantDetails?.name?.toLowerCase().includes(q) ||
      b.dishDetails?.dish_name?.toLowerCase().includes(q) ||
      b.dish?.toLowerCase().includes(q) ||
      b.cuisine?.toLowerCase().includes(q)
    );
  }, [paramFiltered, searchQuery]);

  // ── Sort ────────────────────────────────────────────────────────
  const sorted = useMemo(() => {
    const arr = [...searchFiltered];
    if (sortMode === "rating_desc") arr.sort((a,b) => (parseFloat(b.restaurantDetails?.rating) || 0) - (parseFloat(a.restaurantDetails?.rating) || 0));
    else if (sortMode === "rating_asc") arr.sort((a,b) => (parseFloat(a.restaurantDetails?.rating) || 0) - (parseFloat(b.restaurantDetails?.rating) || 0));
    else if (sortMode === "name_asc") arr.sort((a,b) => (a.restaurantDetails?.name || "").localeCompare(b.restaurantDetails?.name || ""));
    return arr;
  }, [searchFiltered, sortMode]);

  // ── Remove a param filter ────────────────────────────────────────
  const removeCuisine = () => {
    const p = new URLSearchParams(searchParams);
    p.delete("cuisine");
    setSearchParams(p);
  };
  const removeDish = () => {
    const p = new URLSearchParams(searchParams);
    p.delete("dish");
    setSearchParams(p);
  };

  const hasFilters = cuisineParam || dishParam;
  const title = dishParam
    ? dishParam.replace(/\b\w/g, c => c.toUpperCase())
    : cuisineParam
    ? cuisineParam.replace(/\b\w/g, c => c.toUpperCase())
    : "All Restaurants";

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(160deg,#0d0d1a 0%,#150d2e 45%,#0a1628 100%)",
      fontFamily: "'Nunito', sans-serif",
      color: "#fff",
      position: "relative",
      overflowX: "hidden",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&family=Space+Mono:wght@700&display=swap');
        @keyframes cardIn {
          0%   { opacity:0; transform: translateY(24px) scale(0.95); }
          100% { opacity:1; transform: translateY(0) scale(1); }
        }
        @keyframes chipIn {
          0%   { opacity:0; transform: scale(0.7); }
          100% { opacity:1; transform: scale(1); }
        }
        @keyframes fadeUp {
          0%   { opacity:0; transform: translateY(16px); }
          100% { opacity:1; transform: translateY(0); }
        }
        @keyframes headerIn {
          0%   { opacity:0; transform: translateY(-20px); }
          100% { opacity:1; transform: translateY(0); }
        }
        ::placeholder { color: rgba(255,255,255,0.25) !important; }
        * { box-sizing: border-box; }
        ::-webkit-scrollbar { width: 6px; }
        ::-webkit-scrollbar-track { background: transparent; }
        ::-webkit-scrollbar-thumb { background: rgba(255,255,255,0.12); border-radius: 3px; }
      `}</style>

      {/* Ambient glow blobs */}
      <div style={{
        position: "fixed", top: -120, left: -120, width: 500, height: 500, borderRadius: "50%",
        background: `radial-gradient(circle, ${palette.accent}18 0%, transparent 70%)`,
        pointerEvents: "none", zIndex: 0,
      }} />
      <div style={{
        position: "fixed", bottom: -80, right: -80, width: 400, height: 400, borderRadius: "50%",
        background: `radial-gradient(circle, ${palette.accent}10 0%, transparent 70%)`,
        pointerEvents: "none", zIndex: 0,
      }} />

      {/* ── Sticky Header ── */}
      <div style={{
        position: "sticky", top: 0, zIndex: 50,
        background: "rgba(13,13,26,0.82)", backdropFilter: "blur(20px)",
        borderBottom: `1px solid rgba(255,255,255,0.06)`,
        padding: "0 20px",
        animation: "headerIn 0.4s ease both",
      }}>
        <div style={{ maxWidth: 760, margin: "0 auto", padding: "16px 0 0" }}>

          {/* Top row: back + title */}
          <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 14 }}>
            <button
              onClick={() => navigate(-1)}
              style={{
                background: "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.1)",
                borderRadius: 12, padding: "8px 14px", color: "rgba(255,255,255,0.7)",
                cursor: "pointer", fontFamily: "'Nunito',sans-serif", fontWeight: 700,
                fontSize: "0.85rem", display: "flex", alignItems: "center", gap: 6,
                transition: "all 0.2s",
              }}
              onMouseEnter={e => { e.currentTarget.style.background = "rgba(255,255,255,0.1)"; e.currentTarget.style.color = "#fff"; }}
              onMouseLeave={e => { e.currentTarget.style.background = "rgba(255,255,255,0.06)"; e.currentTarget.style.color = "rgba(255,255,255,0.7)"; }}
            >
              <svg width={14} height={14} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth={2.5} strokeLinecap="round">
                <path d="M19 12H5M12 5l-7 7 7 7" />
              </svg>
              Back
            </button>

            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <span style={{ fontSize: "1.5rem" }}>{palette.emoji}</span>
                <h1 style={{
                  margin: 0, fontFamily: "'Nunito',sans-serif", fontWeight: 900,
                  fontSize: "clamp(1.1rem, 3vw, 1.5rem)",
                  background: `linear-gradient(${palette.grad})`,
                  WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent",
                  whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                }}>
                  {title}
                </h1>
              </div>
              <div style={{ color: "rgba(255,255,255,0.35)", fontSize: "0.78rem", fontWeight: 600, marginTop: 1 }}>
                {sorted.length} result{sorted.length !== 1 ? "s" : ""}
                {searchQuery && ` for "${searchQuery}"`}
              </div>
            </div>
          </div>

          {/* Search bar + sort row */}
          <div style={{ display: "flex", gap: 10, marginBottom: 12, alignItems: "stretch" }}>
            <div style={{ flex: 1 }}>
              <SearchBar value={searchQuery} onChange={setSearchQuery} accent={palette.accent} />
            </div>
            <SortSelector value={sortMode} onChange={setSortMode} accent={palette.accent} />
          </div>

          {/* Active filter chips */}
          {hasFilters && (
            <div style={{ display: "flex", flexWrap: "wrap", gap: 8, paddingBottom: 12 }}>
              {cuisineParam && (
                <FilterChip
                  label={`🌍 ${cuisineParam}`}
                  accent={palette.accent}
                  onRemove={removeCuisine}
                />
              )}
              {dishParam && (
                <FilterChip
                  label={`🍽️ ${dishParam}`}
                  accent={palette.accent}
                  onRemove={removeDish}
                />
              )}
            </div>
          )}
        </div>
      </div>

      {/* ── Main content ── */}
      <div style={{
        maxWidth: 760, margin: "0 auto", padding: "28px 20px 80px",
        opacity: mounted ? 1 : 0, transition: "opacity 0.4s ease",
      }}>

        {sorted.length === 0 ? (
          /* Empty state */
          <div style={{
            textAlign: "center", padding: "80px 24px",
            animation: "fadeUp 0.5s ease both",
          }}>
            <div style={{ fontSize: "4rem", marginBottom: 16 }}>
              {searchQuery ? "🔍" : "🍽️"}
            </div>
            <div style={{
              fontFamily: "'Nunito',sans-serif", fontWeight: 800,
              fontSize: "1.15rem", color: "rgba(255,255,255,0.6)", marginBottom: 8,
            }}>
              {searchQuery
                ? `No results for "${searchQuery}"`
                : "No restaurants found"}
            </div>
            <div style={{ color: "rgba(255,255,255,0.3)", fontSize: "0.85rem" }}>
              {searchQuery
                ? "Try a different search term"
                : "Check back after a moment — data is being loaded"}
            </div>
            {searchQuery && (
              <button
                onClick={() => setSearchQuery("")}
                style={{
                  marginTop: 20,
                  background: `${palette.accent}22`, border: `1px solid ${palette.accent}44`,
                  borderRadius: 12, padding: "10px 22px", cursor: "pointer",
                  color: palette.accent, fontFamily: "'Nunito',sans-serif",
                  fontWeight: 700, fontSize: "0.9rem",
                }}
              >
                Clear search
              </button>
            )}
          </div>
        ) : (
          /* Results grid */
          <div style={{
            display: "grid",
            gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))",
            gap: 20,
          }}>
            {sorted.map((item, idx) => (
              <RestaurantCard
                key={`${item.dish_id}-${item.res_id}`}
                item={item}
                idx={idx}
                accent={palette.accent}
                soft={palette.soft}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
